BEGIN;

-- -----------------------------------------------------------
-- sys_dict_type
-- -----------------------------------------------------------
CREATE TABLE "sys_dict_type" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "dict_type" VARCHAR(100) NOT NULL,
    "dict_name" VARCHAR(100) NOT NULL,
    "status" SMALLINT DEFAULT 1,
    "remark" VARCHAR(500) DEFAULT '',
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "sys_dict_type" IS '字典类型表';
COMMENT ON COLUMN "sys_dict_type"."dict_type" IS '字典类型编码';
COMMENT ON COLUMN "sys_dict_type"."dict_name" IS '字典类型名称';
COMMENT ON COLUMN "sys_dict_type"."status" IS '状态 0停用 1启用';
COMMENT ON COLUMN "sys_dict_type"."remark" IS '备注';
ALTER TABLE "sys_dict_type" ADD CONSTRAINT "uk_sys_dict_type_dict_type" UNIQUE ("dict_type");

-- -----------------------------------------------------------
-- sys_dict_data
-- -----------------------------------------------------------
CREATE TABLE "sys_dict_data" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "dict_type" VARCHAR(100) NOT NULL,
    "dict_label" VARCHAR(100) NOT NULL,
    "dict_value" VARCHAR(100) NOT NULL,
    "sort" INTEGER DEFAULT 0,
    "status" SMALLINT DEFAULT 1,
    "remark" VARCHAR(500) DEFAULT '',
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "sys_dict_data" IS '字典数据表';
COMMENT ON COLUMN "sys_dict_data"."dict_type" IS '字典类型编码';
COMMENT ON COLUMN "sys_dict_data"."dict_label" IS '字典标签';
COMMENT ON COLUMN "sys_dict_data"."dict_value" IS '字典值';
COMMENT ON COLUMN "sys_dict_data"."sort" IS '排序';
COMMENT ON COLUMN "sys_dict_data"."status" IS '状态';
COMMENT ON COLUMN "sys_dict_data"."remark" IS '备注';
CREATE INDEX "idx_sys_dict_data_dict_type" ON "sys_dict_data" ("dict_type");

-- -----------------------------------------------------------
-- sys_region
-- -----------------------------------------------------------
CREATE TABLE "sys_region" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "parent_id" BIGINT DEFAULT 0,
    "region_name" VARCHAR(100) NOT NULL,
    "region_level" SMALLINT NOT NULL,
    "region_code" VARCHAR(20),
    "sort" INTEGER DEFAULT 0
);

COMMENT ON TABLE "sys_region" IS '区域字典表';
COMMENT ON COLUMN "sys_region"."parent_id" IS '父级ID';
COMMENT ON COLUMN "sys_region"."region_name" IS '区域名称';
COMMENT ON COLUMN "sys_region"."region_level" IS '层级 1省 2市 3区/县';
COMMENT ON COLUMN "sys_region"."region_code" IS '行政区划代码';
CREATE INDEX "idx_sys_region_parent" ON "sys_region" ("parent_id");

-- -----------------------------------------------------------
-- company
-- -----------------------------------------------------------
CREATE TABLE "company" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "company_name" VARCHAR(200) NOT NULL,
    "company_type" VARCHAR(20) NOT NULL,
    "credit_code" VARCHAR(50),
    "legal_person" VARCHAR(50),
    "contact_name" VARCHAR(50) NOT NULL,
    "contact_phone" VARCHAR(20) NOT NULL,
    "business_license" VARCHAR(500),
    "license_images" JSONB,
    "province_id" BIGINT,
    "city_id" BIGINT,
    "district_id" BIGINT,
    "address" VARCHAR(500),
    "longitude" DECIMAL(10,7),
    "latitude" DECIMAL(10,7),
    "audit_status" VARCHAR(20) DEFAULT 'PENDING',
    "audit_remark" VARCHAR(500),
    "audit_at" TIMESTAMP,
    "audit_by" BIGINT,
    "status" SMALLINT DEFAULT 1,
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "company" IS '公司/企业表（供应商+终端门店）';
COMMENT ON COLUMN "company"."company_name" IS '公司名称';
COMMENT ON COLUMN "company"."company_type" IS '公司类型: SUPPLIER供应商 / MERCHANT终端门店';
COMMENT ON COLUMN "company"."credit_code" IS '统一社会信用代码';
COMMENT ON COLUMN "company"."legal_person" IS '法人代表';
COMMENT ON COLUMN "company"."contact_name" IS '联系人姓名';
COMMENT ON COLUMN "company"."contact_phone" IS '联系人手机号';
COMMENT ON COLUMN "company"."business_license" IS '营业执照URL';
COMMENT ON COLUMN "company"."license_images" IS '资质图片列表';
COMMENT ON COLUMN "company"."province_id" IS '省';
COMMENT ON COLUMN "company"."city_id" IS '市';
COMMENT ON COLUMN "company"."district_id" IS '区';
COMMENT ON COLUMN "company"."address" IS '详细地址';
COMMENT ON COLUMN "company"."longitude" IS '经度（门店用于就近匹配）';
COMMENT ON COLUMN "company"."latitude" IS '纬度';
COMMENT ON COLUMN "company"."audit_status" IS '审核状态: PENDING待审核 / APPROVED通过 / REJECTED驳回';
COMMENT ON COLUMN "company"."audit_remark" IS '审核备注';
COMMENT ON COLUMN "company"."audit_at" IS '审核时间';
COMMENT ON COLUMN "company"."audit_by" IS '审核人';
COMMENT ON COLUMN "company"."status" IS '状态 0停用 1启用';
CREATE INDEX "idx_company_type" ON "company" ("company_type");
CREATE INDEX "idx_company_audit_status" ON "company" ("audit_status");
CREATE INDEX "idx_company_location" ON "company" ("city_id");

-- -----------------------------------------------------------
-- user
-- -----------------------------------------------------------
CREATE TABLE "user" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "company_id" BIGINT NOT NULL,
    "username" VARCHAR(50),
    "password" VARCHAR(200),
    "real_name" VARCHAR(50) NOT NULL,
    "phone" VARCHAR(20) NOT NULL,
    "wechat_openid" VARCHAR(100),
    "wechat_unionid" VARCHAR(100),
    "avatar_url" VARCHAR(500),
    "user_type" VARCHAR(20) NOT NULL,
    "is_master" SMALLINT DEFAULT 0,
    "status" SMALLINT DEFAULT 1,
    "last_login_at" TIMESTAMP,
    "last_login_ip" VARCHAR(50),
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "user" IS '用户表';
COMMENT ON COLUMN "user"."company_id" IS '所属公司';
COMMENT ON COLUMN "user"."username" IS '用户名（子账号登录用）';
COMMENT ON COLUMN "user"."password" IS '密码（加密存储）';
COMMENT ON COLUMN "user"."real_name" IS '真实姓名';
COMMENT ON COLUMN "user"."phone" IS '手机号';
COMMENT ON COLUMN "user"."wechat_openid" IS '微信OpenID';
COMMENT ON COLUMN "user"."wechat_unionid" IS '微信UnionID';
COMMENT ON COLUMN "user"."avatar_url" IS '头像';
COMMENT ON COLUMN "user"."user_type" IS '用户类型: MASTER主账号 / SUB子账号';
COMMENT ON COLUMN "user"."is_master" IS '是否主账号 1是 0否';
COMMENT ON COLUMN "user"."status" IS '状态 0停用 1启用';
COMMENT ON COLUMN "user"."last_login_at" IS '最后登录时间';
COMMENT ON COLUMN "user"."last_login_ip" IS '最后登录IP';
ALTER TABLE "user" ADD CONSTRAINT "uk_user_phone" UNIQUE ("phone");
ALTER TABLE "user" ADD CONSTRAINT "uk_user_username" UNIQUE ("username");
CREATE INDEX "idx_user_company" ON "user" ("company_id");
CREATE INDEX "idx_user_openid" ON "user" ("wechat_openid");

-- -----------------------------------------------------------
-- role
-- -----------------------------------------------------------
CREATE TABLE "role" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "role_name" VARCHAR(100) NOT NULL,
    "role_code" VARCHAR(50) NOT NULL,
    "role_level" SMALLINT DEFAULT 0,
    "company_id" BIGINT DEFAULT NULL,
    "data_scope" VARCHAR(20) DEFAULT 'ALL',
    "remark" VARCHAR(500) DEFAULT '',
    "status" SMALLINT DEFAULT 1,
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "role" IS '角色表（RBAC）';
COMMENT ON COLUMN "role"."role_name" IS '角色名称';
COMMENT ON COLUMN "role"."role_code" IS '角色编码';
COMMENT ON COLUMN "role"."role_level" IS '角色级别 0平台 1公司 2个人';
COMMENT ON COLUMN "role"."company_id" IS '所属公司（公司级角色）';
COMMENT ON COLUMN "role"."data_scope" IS '数据范围: ALL全部 / COMPANY本公司 / CUSTOM自定义';
COMMENT ON COLUMN "role"."remark" IS '备注';
ALTER TABLE "role" ADD CONSTRAINT "uk_role_role_code_company" UNIQUE ("role_code", "company_id");

-- -----------------------------------------------------------
-- permission
-- -----------------------------------------------------------
CREATE TABLE "permission" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "parent_id" BIGINT DEFAULT 0,
    "perm_name" VARCHAR(100) NOT NULL,
    "perm_code" VARCHAR(100),
    "perm_type" VARCHAR(20) NOT NULL,
    "menu_path" VARCHAR(200),
    "menu_icon" VARCHAR(100),
    "sort" INTEGER DEFAULT 0,
    "status" SMALLINT DEFAULT 1,
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "permission" IS '权限表';
COMMENT ON COLUMN "permission"."parent_id" IS '父级ID';
COMMENT ON COLUMN "permission"."perm_name" IS '权限名称';
COMMENT ON COLUMN "permission"."perm_code" IS '权限编码（按钮级别用）';
COMMENT ON COLUMN "permission"."perm_type" IS '类型: MENU菜单 / BUTTON按钮';
COMMENT ON COLUMN "permission"."menu_path" IS '路由地址';
COMMENT ON COLUMN "permission"."menu_icon" IS '菜单图标';
COMMENT ON COLUMN "permission"."sort" IS '排序';
CREATE INDEX "idx_permission_parent" ON "permission" ("parent_id");
CREATE INDEX "idx_permission_code" ON "permission" ("perm_code");

-- -----------------------------------------------------------
-- role_permission
-- -----------------------------------------------------------
CREATE TABLE "role_permission" (
    "role_id" BIGINT NOT NULL,
    "perm_id" BIGINT NOT NULL,
    PRIMARY KEY ("role_id", "perm_id")
);

COMMENT ON TABLE "role_permission" IS '角色权限关联表';

-- -----------------------------------------------------------
-- user_role
-- -----------------------------------------------------------
CREATE TABLE "user_role" (
    "user_id" BIGINT NOT NULL,
    "role_id" BIGINT NOT NULL,
    PRIMARY KEY ("user_id", "role_id")
);

COMMENT ON TABLE "user_role" IS '用户角色关联表';

-- -----------------------------------------------------------
-- sub_account_scope
-- -----------------------------------------------------------
CREATE TABLE "sub_account_scope" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "user_id" BIGINT NOT NULL,
    "scope_type" VARCHAR(20) NOT NULL,
    "scope_value" BIGINT NOT NULL
);

COMMENT ON TABLE "sub_account_scope" IS '子账号数据权限范围';
COMMENT ON COLUMN "sub_account_scope"."user_id" IS '子账号ID';
COMMENT ON COLUMN "sub_account_scope"."scope_type" IS '范围类型: WAREHOUSE仓库 / REGION区域';
COMMENT ON COLUMN "sub_account_scope"."scope_value" IS '范围值（仓库ID或区域ID）';
CREATE INDEX "idx_sub_account_scope_user" ON "sub_account_scope" ("user_id");

-- -----------------------------------------------------------
-- category
-- -----------------------------------------------------------
CREATE TABLE "category" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "parent_id" BIGINT DEFAULT 0,
    "cat_name" VARCHAR(100) NOT NULL,
    "cat_icon" VARCHAR(500),
    "sort" INTEGER DEFAULT 0,
    "status" SMALLINT DEFAULT 1,
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "category" IS '商品分类表（白酒/啤酒/葡萄酒等）';
COMMENT ON COLUMN "category"."parent_id" IS '父级ID';
COMMENT ON COLUMN "category"."cat_name" IS '分类名称';
COMMENT ON COLUMN "category"."cat_icon" IS '分类图标';
COMMENT ON COLUMN "category"."sort" IS '排序';
CREATE INDEX "idx_category_parent" ON "category" ("parent_id");

-- -----------------------------------------------------------
-- brand
-- -----------------------------------------------------------
CREATE TABLE "brand" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "brand_name" VARCHAR(100) NOT NULL,
    "brand_logo" VARCHAR(500),
    "status" SMALLINT DEFAULT 1,
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "brand" IS '品牌表';
COMMENT ON COLUMN "brand"."brand_name" IS '品牌名称';
COMMENT ON COLUMN "brand"."brand_logo" IS '品牌Logo';
ALTER TABLE "brand" ADD CONSTRAINT "uk_brand_brand_name" UNIQUE ("brand_name");

-- -----------------------------------------------------------
-- spu
-- -----------------------------------------------------------
CREATE TABLE "spu" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "category_id" BIGINT NOT NULL,
    "brand_id" BIGINT,
    "spu_name" VARCHAR(200) NOT NULL,
    "spec" VARCHAR(200),
    "unit" VARCHAR(20) DEFAULT '箱',
    "cover_image" VARCHAR(500),
    "images" JSONB,
    "description" TEXT,
    "alcohol_content" DECIMAL(5,2),
    "shelf_life_months" INTEGER,
    "status" SMALLINT DEFAULT 1,
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "spu" IS '商品SPU表';
COMMENT ON COLUMN "spu"."category_id" IS '商品分类';
COMMENT ON COLUMN "spu"."brand_id" IS '品牌';
COMMENT ON COLUMN "spu"."spu_name" IS '商品名称';
COMMENT ON COLUMN "spu"."spec" IS '规格（500ml/750ml等）';
COMMENT ON COLUMN "spu"."unit" IS '单位（箱/瓶）';
COMMENT ON COLUMN "spu"."cover_image" IS '封面图';
COMMENT ON COLUMN "spu"."images" IS '商品图片列表';
COMMENT ON COLUMN "spu"."description" IS '商品描述';
COMMENT ON COLUMN "spu"."alcohol_content" IS '酒精度';
COMMENT ON COLUMN "spu"."shelf_life_months" IS '保质期(月)，NULL表示无固定保质期（如白酒长期保存）';
COMMENT ON COLUMN "spu"."status" IS '状态 0下架 1上架';
CREATE INDEX "idx_spu_category" ON "spu" ("category_id");
CREATE INDEX "idx_spu_brand" ON "spu" ("brand_id");

-- -----------------------------------------------------------
-- supplier_product
-- -----------------------------------------------------------
CREATE TABLE "supplier_product" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "supplier_id" BIGINT NOT NULL,
    "spu_id" BIGINT NOT NULL,
    "product_name" VARCHAR(200) NOT NULL,
    "cover_image" VARCHAR(500),
    "base_price" DECIMAL(12,2) NOT NULL,
    "min_order_qty" INTEGER DEFAULT 1,
    "status" VARCHAR(20) DEFAULT 'ON_SHELF',
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "supplier_product" IS '供应商商品/SKU表';
COMMENT ON COLUMN "supplier_product"."supplier_id" IS '供应商公司ID';
COMMENT ON COLUMN "supplier_product"."spu_id" IS '商品SPU ID';
COMMENT ON COLUMN "supplier_product"."product_name" IS '供应商自定义商品名';
COMMENT ON COLUMN "supplier_product"."cover_image" IS '商品配图';
COMMENT ON COLUMN "supplier_product"."base_price" IS '基础售价（元）';
COMMENT ON COLUMN "supplier_product"."min_order_qty" IS '最小起订量';
COMMENT ON COLUMN "supplier_product"."status" IS '状态: ON_SHELF上架 / OFF_SHELF下架';
CREATE INDEX "idx_supplier_product_supplier" ON "supplier_product" ("supplier_id");
CREATE INDEX "idx_supplier_product_spu" ON "supplier_product" ("spu_id");
CREATE INDEX "idx_supplier_product_status" ON "supplier_product" ("status");

-- -----------------------------------------------------------
-- price_tier
-- -----------------------------------------------------------
CREATE TABLE "price_tier" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "supplier_product_id" BIGINT NOT NULL,
    "min_qty" INTEGER NOT NULL,
    "max_qty" INTEGER NOT NULL,
    "unit_price" DECIMAL(12,2) NOT NULL,
    "sort" INTEGER DEFAULT 0,
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "price_tier" IS '商品阶梯价表';
COMMENT ON COLUMN "price_tier"."supplier_product_id" IS '供应商商品ID';
COMMENT ON COLUMN "price_tier"."min_qty" IS '最低购买数量';
COMMENT ON COLUMN "price_tier"."max_qty" IS '最高购买数量';
COMMENT ON COLUMN "price_tier"."unit_price" IS '阶梯单价（元）';
COMMENT ON COLUMN "price_tier"."sort" IS '档位排序';
CREATE INDEX "idx_price_tier_product" ON "price_tier" ("supplier_product_id");

-- -----------------------------------------------------------
-- bundle
-- -----------------------------------------------------------
CREATE TABLE "bundle" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "supplier_id" BIGINT NOT NULL,
    "bundle_name" VARCHAR(200) NOT NULL,
    "bundle_image" VARCHAR(500),
    "bundle_price" DECIMAL(12,2) NOT NULL,
    "bundle_desc" TEXT,
    "status" VARCHAR(20) DEFAULT 'ON_SHELF',
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "bundle" IS '商品套餐表';
COMMENT ON COLUMN "bundle"."supplier_id" IS '供应商ID';
COMMENT ON COLUMN "bundle"."bundle_name" IS '套餐名称';
COMMENT ON COLUMN "bundle"."bundle_image" IS '套餐图片';
COMMENT ON COLUMN "bundle"."bundle_price" IS '套餐售价';
COMMENT ON COLUMN "bundle"."bundle_desc" IS '套餐描述';
COMMENT ON COLUMN "bundle"."status" IS '状态: ON_SHELF上架 / OFF_SHELF下架';
CREATE INDEX "idx_bundle_supplier" ON "bundle" ("supplier_id");
CREATE INDEX "idx_bundle_status" ON "bundle" ("status");

-- -----------------------------------------------------------
-- bundle_product
-- -----------------------------------------------------------
CREATE TABLE "bundle_product" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "bundle_id" BIGINT NOT NULL,
    "supplier_product_id" BIGINT NOT NULL,
    "quantity" INTEGER NOT NULL
);

COMMENT ON TABLE "bundle_product" IS '套餐商品明细表';
COMMENT ON COLUMN "bundle_product"."bundle_id" IS '套餐ID';
COMMENT ON COLUMN "bundle_product"."supplier_product_id" IS '供应商商品ID';
COMMENT ON COLUMN "bundle_product"."quantity" IS '数量';
CREATE INDEX "idx_bundle_product_bundle" ON "bundle_product" ("bundle_id");

-- -----------------------------------------------------------
-- quotation
-- -----------------------------------------------------------
CREATE TABLE "quotation" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "supplier_id" BIGINT NOT NULL,
    "user_id" BIGINT NOT NULL,
    "quotation_no" VARCHAR(50) NOT NULL,
    "title" VARCHAR(200) NOT NULL,
    "source_type" VARCHAR(20) NOT NULL,
    "content_text" TEXT,
    "attachment_urls" JSONB,
    "status" VARCHAR(20) DEFAULT 'PUBLISHED',
    "archived_at" TIMESTAMP,
    "archived_by" BIGINT,
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "quotation" IS '报价单表';
COMMENT ON COLUMN "quotation"."supplier_id" IS '供应商ID';
COMMENT ON COLUMN "quotation"."user_id" IS '提交人ID';
COMMENT ON COLUMN "quotation"."quotation_no" IS '报价单号';
COMMENT ON COLUMN "quotation"."title" IS '报价标题';
COMMENT ON COLUMN "quotation"."source_type" IS '来源: TEXT文本 / IMAGE图片 / EXCEL表格';
COMMENT ON COLUMN "quotation"."content_text" IS '文本内容';
COMMENT ON COLUMN "quotation"."attachment_urls" IS '附件列表（图片/Excel）';
COMMENT ON COLUMN "quotation"."status" IS '状态: PUBLISHED已发布 / ARCHIVED已归档';
COMMENT ON COLUMN "quotation"."archived_at" IS '归档时间';
COMMENT ON COLUMN "quotation"."archived_by" IS '归档人';
ALTER TABLE "quotation" ADD CONSTRAINT "uk_quotation_quotation_no" UNIQUE ("quotation_no");
CREATE INDEX "idx_quotation_supplier" ON "quotation" ("supplier_id");
CREATE INDEX "idx_quotation_status" ON "quotation" ("status");

-- -----------------------------------------------------------
-- quotation_item
-- -----------------------------------------------------------
CREATE TABLE "quotation_item" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "quotation_id" BIGINT NOT NULL,
    "spu_id" BIGINT,
    "product_name" VARCHAR(200) NOT NULL,
    "spec" VARCHAR(100),
    "price" DECIMAL(12,2) NOT NULL,
    "stock_qty" INTEGER,
    "warehouse_id" BIGINT
);

COMMENT ON TABLE "quotation_item" IS '报价明细表';
COMMENT ON COLUMN "quotation_item"."quotation_id" IS '报价单ID';
COMMENT ON COLUMN "quotation_item"."spu_id" IS '商品SPU';
COMMENT ON COLUMN "quotation_item"."product_name" IS '商品名称';
COMMENT ON COLUMN "quotation_item"."spec" IS '规格';
COMMENT ON COLUMN "quotation_item"."price" IS '报价价格';
COMMENT ON COLUMN "quotation_item"."stock_qty" IS '库存数量';
COMMENT ON COLUMN "quotation_item"."warehouse_id" IS '所在仓库';
CREATE INDEX "idx_quotation_item_quotation" ON "quotation_item" ("quotation_id");

-- -----------------------------------------------------------
-- market_price
-- -----------------------------------------------------------
CREATE TABLE "market_price" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "spu_id" BIGINT NOT NULL,
    "price_date" DATE NOT NULL,
    "latest_price" DECIMAL(12,2),
    "highest_price" DECIMAL(12,2),
    "lowest_price" DECIMAL(12,2),
    "avg_price" DECIMAL(12,2),
    "change_percent" DECIMAL(8,2),
    "change_amount" DECIMAL(12,2),
    "supplier_count" INTEGER DEFAULT 0,
    "is_manual" SMALLINT DEFAULT 0,
    "remark" VARCHAR(500),
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "market_price" IS '每日行情数据表';
COMMENT ON COLUMN "market_price"."spu_id" IS '商品SPU';
COMMENT ON COLUMN "market_price"."price_date" IS '行情日期';
COMMENT ON COLUMN "market_price"."latest_price" IS '最新报价（当日最低）';
COMMENT ON COLUMN "market_price"."highest_price" IS '当日最高价';
COMMENT ON COLUMN "market_price"."lowest_price" IS '当日最低价';
COMMENT ON COLUMN "market_price"."avg_price" IS '当日均价';
COMMENT ON COLUMN "market_price"."change_percent" IS '涨跌幅(%)';
COMMENT ON COLUMN "market_price"."change_amount" IS '涨跌金额';
COMMENT ON COLUMN "market_price"."supplier_count" IS '报价供应商数';
COMMENT ON COLUMN "market_price"."is_manual" IS '是否人工干预 1是 0否';
COMMENT ON COLUMN "market_price"."remark" IS '备注（干预原因）';
CREATE INDEX "idx_market_price_spu_date" ON "market_price" ("spu_id", "price_date");
CREATE INDEX "idx_market_price_date" ON "market_price" ("price_date");

-- -----------------------------------------------------------
-- warehouse
-- -----------------------------------------------------------
CREATE TABLE "warehouse" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "warehouse_name" VARCHAR(200) NOT NULL,
    "warehouse_code" VARCHAR(50) NOT NULL,
    "warehouse_type" VARCHAR(20) NOT NULL,
    "owner_id" BIGINT,
    "province_id" BIGINT,
    "city_id" BIGINT,
    "district_id" BIGINT,
    "address" VARCHAR(500),
    "longitude" DECIMAL(10,7) NOT NULL,
