    "response_result" TEXT,
    "ip_address" VARCHAR(50),
    "user_agent" VARCHAR(500),
    "cost_time" BIGINT,
    "status" SMALLINT DEFAULT 1,
    "error_msg" TEXT,
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "operation_log" IS '操作日志表';
