COMMENT ON COLUMN "operation_log"."company_id" IS '所属公司';
COMMENT ON COLUMN "operation_log"."module" IS '操作模块';
COMMENT ON COLUMN "operation_log"."operation" IS '操作类型';
COMMENT ON COLUMN "operation_log"."method" IS '请求方法';
COMMENT ON COLUMN "operation_log"."request_url" IS '请求URL';
COMMENT ON COLUMN "operation_log"."request_params" IS '请求参数';
COMMENT ON COLUMN "operation_log"."response_result" IS '返回结果';
COMMENT ON COLUMN "operation_log"."ip_address" IS '操作IP';
COMMENT ON COLUMN "operation_log"."user_agent" IS '浏览器UA';
COMMENT ON COLUMN "operation_log"."cost_time" IS '耗时(ms)';
COMMENT ON COLUMN "operation_log"."status" IS '状态 0失败 1成功';
