CREATE TABLE "wallet" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "owner_id" BIGINT NOT NULL,
    "owner_type" VARCHAR(20) NOT NULL,
    "balance" DECIMAL(14,2) DEFAULT 0,
