COMMENT ON COLUMN "wallet"."total_income" IS '累计收入';
COMMENT ON COLUMN "wallet"."total_outcome" IS '累计支出';
COMMENT ON COLUMN "wallet"."status" IS '状态: ACTIVE正常 / FROZEN冻结';
ALTER TABLE "wallet" ADD CONSTRAINT "uk_wallet_owner" UNIQUE ("owner_id", "owner_type");
CREATE INDEX "idx_wallet_balance" ON "wallet" ("balance");

