-- supplier_review
-- -----------------------------------------------------------
CREATE TABLE "supplier_review" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "order_id" BIGINT NOT NULL,
    "supplier_id" BIGINT NOT NULL,
    "buyer_id" BIGINT NOT NULL,
    "quality_score" SMALLINT NOT NULL,
    "delivery_score" SMALLINT NOT NULL,
    "service_score" SMALLINT NOT NULL,
    "review_content" VARCHAR(1000),
    "review_images" JSONB,
    "is_anonymous" SMALLINT DEFAULT 0,
    "reply_content" VARCHAR(1000),
    "reply_at" TIMESTAMP,
    "appeal_content" VARCHAR(1000),
    "appeal_status" VARCHAR(20),
    "status" VARCHAR(20) DEFAULT 'PUBLISHED',
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "supplier_review" IS '供应商评价表（旗舰版）';
COMMENT ON COLUMN "supplier_review"."order_id" IS '订单ID';
COMMENT ON COLUMN "supplier_review"."supplier_id" IS '供应商ID';
COMMENT ON COLUMN "supplier_review"."buyer_id" IS '评价人（门店）';
COMMENT ON COLUMN "supplier_review"."quality_score" IS '商品质量评分 1-5';
COMMENT ON COLUMN "supplier_review"."delivery_score" IS '配送时效评分 1-5';
COMMENT ON COLUMN "supplier_review"."service_score" IS '服务态度评分 1-5';
COMMENT ON COLUMN "supplier_review"."review_content" IS '评价内容';
COMMENT ON COLUMN "supplier_review"."review_images" IS '评价图片';
COMMENT ON COLUMN "supplier_review"."is_anonymous" IS '是否匿名 1是 0否';
COMMENT ON COLUMN "supplier_review"."reply_content" IS '供应商回复';
COMMENT ON COLUMN "supplier_review"."reply_at" IS '回复时间';
COMMENT ON COLUMN "supplier_review"."appeal_content" IS '申诉内容';
COMMENT ON COLUMN "supplier_review"."appeal_status" IS '申诉状态: NONE无 / PENDING待处理 / ACCEPTED已受理 / REJECTED已驳回';
COMMENT ON COLUMN "supplier_review"."status" IS '状态: PUBLISHED已发布 / HIDDEN已隐藏';
CREATE INDEX "idx_supplier_review_supplier" ON "supplier_review" ("supplier_id");
CREATE INDEX "idx_supplier_review_order" ON "supplier_review" ("order_id");
CREATE INDEX "idx_supplier_review_scores" ON "supplier_review" ("quality_score", "delivery_score", "service_score");

-- -----------------------------------------------------------
-- audit_log
-- -----------------------------------------------------------
CREATE TABLE "audit_log" (
    "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "user_id" BIGINT,
    "company_id" BIGINT,
    "event_type" VARCHAR(50) NOT NULL,
    "event_detail" TEXT,
    "target_type" VARCHAR(50),
    "target_id" BIGINT,
    "ip_address" VARCHAR(50),
    "user_agent" VARCHAR(500),
    "geo_location" VARCHAR(200),
    "risk_level" VARCHAR(20) DEFAULT 'LOW',
    "result" VARCHAR(20) DEFAULT 'SUCCESS',
    "created_at" TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE "audit_log" IS '审计日志表（旗舰版）';
COMMENT ON COLUMN "audit_log"."user_id" IS '操作人';
COMMENT ON COLUMN "audit_log"."company_id" IS '所属公司';
COMMENT ON COLUMN "audit_log"."event_type" IS '事件类型: LOGIN登录 / LOGOUT登出 / PERM_CHANGE权限变更 / SENSITIVE敏感操作 / ABNORMAL异常行为';
COMMENT ON COLUMN "audit_log"."event_detail" IS '事件详情';
COMMENT ON COLUMN "audit_log"."target_type" IS '操作对象类型';
COMMENT ON COLUMN "audit_log"."target_id" IS '操作对象ID';
COMMENT ON COLUMN "audit_log"."ip_address" IS 'IP地址';
COMMENT ON COLUMN "audit_log"."user_agent" IS 'UA';
COMMENT ON COLUMN "audit_log"."geo_location" IS '地理位置';
COMMENT ON COLUMN "audit_log"."risk_level" IS '风险等级: LOW低 / MEDIUM中 / HIGH高 / CRITICAL严重';
COMMENT ON COLUMN "audit_log"."result" IS '结果: SUCCESS成功 / FAILED失败 / BLOCKED被拦截';
CREATE INDEX "idx_audit_log_user" ON "audit_log" ("user_id");
CREATE INDEX "idx_audit_log_event" ON "audit_log" ("event_type");
CREATE INDEX "idx_audit_log_risk" ON "audit_log" ("risk_level");
CREATE INDEX "idx_audit_log_created" ON "audit_log" ("created_at");


COMMIT;

-- 共 47 张表
-- 转换说明:
--   AUTO_INCREMENT → GENERATED BY DEFAULT AS IDENTITY
--   TINYINT → SMALLINT
--   DATETIME → TIMESTAMP
--   JSON → JSONB
--   KEY → CREATE INDEX
--   UNIQUE KEY → ALTER TABLE ADD CONSTRAINT UNIQUE
--   ON UPDATE CURRENT_TIMESTAMP → 需单独创建触发器
-- ============================================================
